99	#[test]
100	fn build_sh_bundles_both_ort_libraries() {
101	    let src = read_file("packaging/appimage/build.sh");
102	    assert!(
103	        src.contains("libonnxruntime.so"),
104	        "build.sh must reference libonnxruntime.so for dual-ORT bundling"
105	    );
106	    assert!(
107	        src.contains("libsherpa-onnx-c-api.so"),
108	        "build.sh must reference libsherpa-onnx-c-api.so for dual-ORT bundling"
109	    );
110	}
